// ============================================
// CUSTOM JAVASCRIPT LOGIC FOR MEASUREMENT DATA
// ============================================
// This code demonstrates various ways to process measurement data:
// 1. Access and transform the incoming data
// 2. Send data to external APIs
// 3. Store files in S3 (or other cloud storage)
// 4. Trigger other n8n workflows
// 5. Perform custom calculations and filtering

// ============================================
// 1. ACCESS INCOMING MEASUREMENT DATA
// ============================================
// Get all items from the previous node
const items = $input.all();

// Access the first item's data
const firstItem = items[0].json;
console.log('First measurement:', firstItem);

// Example: Access specific fields from the measurement data
// Assuming structure: { timestamp, sensorId, temperature, humidity, pressure }
const measurements = items.map(item => ({
  timestamp: item.json.timestamp,
  sensorId: item.json.sensorId,
  temperature: item.json.temperature,
  humidity: item.json.humidity,
  pressure: item.json.pressure
}));

console.log('Processed measurements:', measurements);

// ============================================
// 2. SEND DATA TO EXTERNAL API
// ============================================
// Example: Send measurement data to a custom API endpoint
const apiResults = [];

for (const measurement of measurements) {
  try {
    // Make HTTP request to external API
    const response = await $http.request({
      method: 'POST',
      url: 'https://api.example.com/measurements',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': 'Bearer YOUR_TOKEN_HERE'
      },
      body: {
        sensor_id: measurement.sensorId,
        timestamp: measurement.timestamp,
        readings: {
          temperature: measurement.temperature,
          humidity: measurement.humidity,
          pressure: measurement.pressure
        }
      }
    });

    apiResults.push({
      success: true,
      sensorId: measurement.sensorId,
      apiResponse: response
    });
  } catch (error) {
    console.error('API Error:', error);
    apiResults.push({
      success: false,
      sensorId: measurement.sensorId,
      error: error.message
    });
  }
}

// ============================================
// 3. STORE DATA IN AWS S3 (OR OTHER STORAGE)
// ============================================
// Example: Prepare data for S3 upload
const csvData = measurements.map(m => 
  `${m.timestamp},${m.sensorId},${m.temperature},${m.humidity},${m.pressure}`
).join('\n');

const csvWithHeader = 'Timestamp,Sensor ID,Temperature,Humidity,Pressure\n' + csvData;

// Create a filename with current date
const filename = `measurements_${new Date().toISOString().split('T')[0]}.csv`;

// Note: To actually upload to S3, you would use the AWS S3 node or make an API call
// This example shows how to prepare the data
const s3Payload = {
  bucket: 'your-bucket-name',
  key: `measurements/${filename}`,
  content: csvWithHeader,
  contentType: 'text/csv'
};

console.log('S3 upload payload prepared:', s3Payload);

// ============================================
// 4. TRIGGER ANOTHER N8N WORKFLOW
// ============================================
// Example: Trigger another workflow via webhook
const workflowTriggerResults = [];

// Only trigger if temperature exceeds threshold
const highTempMeasurements = measurements.filter(m => m.temperature > 30);

if (highTempMeasurements.length > 0) {
  try {
    const triggerResponse = await $http.request({
      method: 'POST',
      url: 'https://avikadam.app.n8n.cloud/webhook/alert-workflow',
      headers: {
        'Content-Type': 'application/json'
      },
      body: {
        alertType: 'HIGH_TEMPERATURE',
        measurements: highTempMeasurements,
        triggeredAt: new Date().toISOString()
      }
    });

    workflowTriggerResults.push({
      triggered: true,
      count: highTempMeasurements.length,
      response: triggerResponse
    });
  } catch (error) {
    console.error('Workflow trigger error:', error);
    workflowTriggerResults.push({
      triggered: false,
      error: error.message
    });
  }
}

// ============================================
// 5. CUSTOM CALCULATIONS AND FILTERING
// ============================================
// Calculate statistics
const temperatures = measurements.map(m => m.temperature);
const avgTemp = temperatures.reduce((a, b) => a + b, 0) / temperatures.length;
const maxTemp = Math.max(...temperatures);
const minTemp = Math.min(...temperatures);

const statistics = {
  totalMeasurements: measurements.length,
  averageTemperature: avgTemp.toFixed(2),
  maxTemperature: maxTemp,
  minTemperature: minTemp,
  highTempAlerts: highTempMeasurements.length,
  processedAt: new Date().toISOString()
};

console.log('Statistics:', statistics);

// ============================================
// 6. RETURN PROCESSED DATA
// ============================================
// Return all processed data as output
return [
  {
    json: {
      summary: statistics,
      measurements: measurements,
      apiResults: apiResults,
      s3Upload: s3Payload,
      workflowTriggers: workflowTriggerResults,
      processedCount: measurements.length
    }
  }
];

